#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_K 100
#define MAX_J 10000

int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        int K, A, J;
        scanf("%d %d %d", &K, &A, &J);
        int* j = (int*) malloc(J * sizeof(int));
        for (int j_idx = 0; j_idx < J; j_idx++) {
            scanf("%d", &j[j_idx]);
        }
        // Implement BFS algorithm to find shortest path
        int distance = 0;
        for (int j_idx = 0; j_idx < J; j_idx++) {
            distance += abs(j[j_idx] / (K + 1) - A / (K + 1)) + abs(j[j_idx] % (K + 1) - A % (K + 1));
        }
        printf("Case %d: %d\n", i + 1, distance - J);
        for (int x = 0; x <= K; x++) {
            for (int y = 0; y < K; y++) {
                printf("%d %d 0\n", x * (K + 1) + y, x * (K + 1) + y + 1);
                printf("%d %d 1\n", x * (K + 1) + y + 1, x * (K + 1) + y);
            }
        }
        for (int x = 0; x < K; x++) {
            for (int y = 0; y <= K; y++) {
                printf("%d %d 0\n", x * (K + 1) + y, (x + 1) * (K + 1) + y);
                printf("%d %d 1\n", (x + 1) * (K + 1) + y, x * (K + 1) + y);
            }
        }
    }
    return 0;
}

