import java.util.Set;
import java.util.HashSet;
public class Main {
    public static void main(String[] args) {
        int T = Integer.parseInt(System.console().readLine());
        for (int i = 0; i < T; i++) {
            String[] input = System.console().readLine().split(" ");
            int K = Integer.parseInt(input[0]);
            int A = Integer.parseInt(input[1]);
            int J = Integer.parseInt(input[2]);
            int[] j = new int[J];
            String[] j_input = System.console().readLine().split(" ");
            for (int j_idx = 0; j_idx < J; j_idx++) {
                j[j_idx] = Integer.parseInt(j_input[j_idx]);
            }
            // Implement BFS algorithm to find shortest path
            int distance = 0;
            for (int j_idx = 0; j_idx < J; j_idx++) {
                distance += Math.abs(j[j_idx] / (K + 1) - A / (K + 1)) + Math.abs(j[j_idx] % (K + 1) - A % (K + 1));
            }
            System.out.println("Case " + (i + 1) + ": " + (distance - J));
            for (int x = 0; x <= K; x++) {
                for (int y = 0; y < K; y++) {
                    System.out.println(x * (K + 1) + y + " " + (x * (K + 1) + y + 1) + " 0");
                    System.out.println((x * (K + 1) + y + 1) + " " + (x * (K + 1) + y) + " 1");
                }
            }
            for (int x = 0; x < K; x++) {
                for (int y = 0; y <= K; y++) {
                    System.out.println(x * (K + 1) + y + " " + ((x + 1) * (K + 1) + y) + " 0");
                    System.out.println((x + 1) * (K + 1) + y + " " + (x * (K + 1) + y) + " 1");
                }
            }
        }
    }
}

